function writeFile(rel, content) {
  const full = path.join(root, rel);
  fs.mkdirSync(path.dirname(full), { recursive: true });
  fs.writeFileSync(full, content.split('\n').join('\r\n'), 'utf8');
  console.log('WROTE', rel);
}

for (const [rel, content] of Object.entries(files)) writeFile(rel, content);

function run(cmd, args) {
  console.log('RUN', cmd, args.join(' '));
  const result = spawnSync(cmd, args, { cwd: root, stdio: 'inherit', shell: process.platform === 'win32' });
  if (result.status !== 0) {
    console.error('FAILED:', cmd, args.join(' '));
    process.exit(result.status ?? 1);
  }
}

if (!process.argv.includes('--skip-build')) {
  run('pnpm', ['--filter', '@allinall/erp', 'build']);
  run('pnpm', ['--filter', '@allinall/api', 'build']);
}

